ALTER TABLE public.advance_applications ADD CONSTRAINT advance_applications_customer_id_fkey FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL;
ALTER TABLE public.advance_applications ADD CONSTRAINT advance_applications_invoice_id_fkey FOREIGN KEY (invoice_id) REFERENCES invoices(id) ON DELETE SET NULL;
ALTER TABLE public.advance_applications ADD CONSTRAINT advance_applications_payment_id_fkey FOREIGN KEY (payment_id) REFERENCES payments(id) ON DELETE CASCADE;
ALTER TABLE public.advance_applications ADD CONSTRAINT advance_applications_pkey PRIMARY KEY (id);
ALTER TABLE public.advance_applications ADD CONSTRAINT advance_applications_supplier_id_fkey FOREIGN KEY (supplier_id) REFERENCES suppliers(id) ON DELETE SET NULL;
