-- ---- policies ----
CREATE POLICY account_balances_insert ON public.account_balances AS PERMISSIVE FOR INSERT TO public WITH CHECK (can_modify_data(company_id));
CREATE POLICY account_balances_owner_dml ON public.account_balances AS PERMISSIVE FOR ALL TO public USING ((company_id IN ( SELECT companies.id
   FROM companies
  WHERE (companies.user_id = auth.uid())))) WITH CHECK ((company_id IN ( SELECT companies.id
   FROM companies
  WHERE (companies.user_id = auth.uid()))));
CREATE POLICY account_balances_owner_select ON public.account_balances AS PERMISSIVE FOR SELECT TO public USING ((company_id IN ( SELECT companies.id
   FROM companies
  WHERE (companies.user_id = auth.uid()))));
CREATE POLICY account_balances_select ON public.account_balances AS PERMISSIVE FOR SELECT TO public USING (is_company_member(company_id));
CREATE POLICY account_balances_update ON public.account_balances AS PERMISSIVE FOR UPDATE TO public USING (can_modify_data(company_id));
CREATE POLICY accounting_periods_insert ON public.accounting_periods AS PERMISSIVE FOR INSERT TO public WITH CHECK ((EXISTS ( SELECT 1
   FROM company_members cm
  WHERE ((cm.company_id = accounting_periods.company_id) AND (cm.user_id = auth.uid()) AND (cm.role = ANY (ARRAY['owner'::text, 'admin'::text]))))));
CREATE POLICY accounting_periods_select ON public.accounting_periods AS PERMISSIVE FOR SELECT TO public USING ((EXISTS ( SELECT 1
   FROM company_members cm
  WHERE ((cm.company_id = accounting_periods.company_id) AND (cm.user_id = auth.uid())))));
CREATE POLICY accounting_periods_update ON public.accounting_periods AS PERMISSIVE FOR UPDATE TO public USING ((EXISTS ( SELECT 1
   FROM company_members cm
