CREATE POLICY customers_select_v5 ON public.customers AS PERMISSIVE FOR SELECT TO public USING ((is_company_member(company_id) AND ((current_user_resource_visibility(company_id, 'customers'::text) = 'company'::text) OR ((current_user_resource_visibility(company_id, 'customers'::text) = 'branch'::text) AND ((branch_id IS NULL) OR (branch_id = current_user_branch_id(company_id)))) OR ((current_user_resource_visibility(company_id, 'customers'::text) = 'own'::text) AND (created_by_user_id = auth.uid())) OR has_shared_access(company_id, 'customers'::text, created_by_user_id) OR ((EXISTS ( SELECT 1
   FROM company_members cm
  WHERE ((cm.user_id = auth.uid()) AND (cm.company_id = customers.company_id) AND (cm.role = ANY (ARRAY['store_manager'::text, 'manufacturing_officer'::text, 'purchasing_officer'::text, 'accountant'::text, 'manager'::text, 'hr_officer'::text]))))) AND (EXISTS ( SELECT 1
   FROM invoices i
  WHERE ((i.customer_id = customers.id) AND (i.company_id = customers.company_id) AND ((i.branch_id IS NULL) OR (i.branch_id = current_user_branch_id(customers.company_id))))))))));
